                    let res = search(&node.right, v);
                    // Help the solver conclude that v cannot be in the left subtree
                    if let Some(left) = &node.left {
                        assert(left.view().contains(v) ==> v < node.val);
                    }
                    res
                }
            }
        }
    }
    // </code>

    #[verifier::external]
    fn main() {}
